class Solution {
    public long validSubstringCount(String word1, String word2) {
        int[] count1 = new int[26];
        int[] count2 = new int[26];
        for (char c : word2.toCharArray()) {
            count2[c - 'a']++;
        }
        int required = 0;
        for (int i = 0; i < 26; i++) {
            if (count2[i] > 0) {
                required++;
            }
        }
        int left = 0;
        int formed = 0;
        long ans = 0;
        for (int right = 0; right < word1.length(); right++) {
            char c = word1.charAt(right);
            count1[c - 'a']++;
            if (count1[c - 'a'] == count2[c - 'a']) {
                formed++;
            }
            while (formed == required && left <= right) {
                ans += word1.length() - right;
                char cl = word1.charAt(left);
                count1[cl - 'a']--;
                if (count1[cl - 'a'] < count2[cl - 'a']) {
                    formed--;
                }
                left++;
            }
        }
        return ans;
    }
